import { AsyncPipe, CurrencyPipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { combineLatest, map, tap } from 'rxjs';
import { ArtworkCardComponent } from '../../components/artwork-card/artwork-card.component';
import { HeroComponent } from '../../components/hero/hero.component';
import { ArtworkService } from '../../services/artwork.service';
import { CommissionsContent } from '../../interfaces/commissions-content.interface';
import { LanguageService } from '../../services/language.service';
import { SeoService } from '../../services/seo.service';
import { SiteService } from '../../services/site.service';
import { COMMISSIONS_CONTENT } from '../../../content/commissions.content';
import { RevealOnScrollDirective } from '../../directives/reveal-on-scroll.directive';

@Component({
  selector: 'app-commissions-page',
  standalone: true,
  imports: [AsyncPipe, CurrencyPipe, RouterLink, HeroComponent, ArtworkCardComponent, RevealOnScrollDirective],
  templateUrl: './commissions.page.html',
  styleUrl: './commissions.page.sass'
})
export class CommissionsPage {
  private readonly siteService = inject(SiteService);
  private readonly artworkService = inject(ArtworkService);
  private readonly languageService = inject(LanguageService);
  private readonly seoService = inject(SeoService);
  private readonly route = inject(ActivatedRoute);
  protected selectedWidthCm: number | null = null;
  protected selectedHeightCm: number | null = null;

  protected readonly vm$ = combineLatest([
    this.siteService.getSiteConfig(),
    this.siteService.getPagesConfig(),
    this.artworkService.getArtworks()
  ]).pipe(
    map(([siteConfig, pagesConfig, artworks]) => {
      const language = this.languageService.getRouteLanguage(this.route.snapshot);
      const featuredArtworkIds = Array.isArray(pagesConfig.commissions.featuredArtworkIds)
        ? pagesConfig.commissions.featuredArtworkIds
        : [];
      const widthOptions = this.buildDimensionOptions(siteConfig.commissions);
      const heightOptions = this.buildDimensionOptions(siteConfig.commissions);
      const featuredWorks = artworks.filter((artwork) => featuredArtworkIds.includes(artwork.id));

      return {
        siteConfig,
        pagesConfig,
        language,
        content: this.buildPageContent(pagesConfig),
        contactsPath: this.languageService.buildLocalizedPath(language, 'contacts'),
        currencyLocale: language === 'it' ? 'it' : 'en',
        widthOptions,
        heightOptions,
        featuredWorks
      };
    }),
    tap(({ siteConfig, language }) => {
      this.seoService.applyLocalizedAlternates(
        siteConfig.domain,
        this.route.snapshot,
        undefined,
        siteConfig.defaultLanguage
      );

      this.seoService.applyPageMetadata({
        title: language === 'en' ? `Commissions | ${siteConfig.artistName}` : `Commissioni | ${siteConfig.artistName}`,
        description:
          language === 'en'
            ? `Commissioned artworks and bespoke requests for collectors, interiors and curatorial projects.`
            : `Opere su commissione e richieste personalizzate per collezionisti, interni e progetti curatoriali.`,
        url: `${siteConfig.domain}${this.languageService.buildLocalizedPath(language, 'commissions')}`,
        image: `${siteConfig.domain}${siteConfig.seo.defaultOgImage}`,
        siteName: siteConfig.artistName,
        language
      });
    })
  );

  protected onWidthChange(rawValue: string): void {
    const parsed = Number(rawValue);
    this.selectedWidthCm = Number.isFinite(parsed) ? parsed : null;
  }

  protected onHeightChange(rawValue: string): void {
    const parsed = Number(rawValue);
    this.selectedHeightCm = Number.isFinite(parsed) ? parsed : null;
  }

  protected getSelectedWidth(options: number[]): number {
    return this.resolveSelectedValue(this.selectedWidthCm, options, 30);
  }

  protected getSelectedHeight(options: number[]): number {
    return this.resolveSelectedValue(this.selectedHeightCm, options, 40);
  }

  protected calculateEstimate(rate: number, widthCm: number, heightCm: number): number {
    return Math.round(rate * widthCm * heightCm * 100) / 100;
  }

  protected calculateDeposit(amount: number): number {
    return Math.round(amount * 0.68 * 100) / 100;
  }

  protected calculateBalance(amount: number): number {
    return Math.round(amount * 0.32 * 100) / 100;
  }

  protected isFormatAvailable(
    widthCm: number,
    heightCm: number,
    config: { minWidthCm: number; minHeightCm: number; maxWidthCm: number; maxHeightCm: number }
  ): boolean {
    const shortSide = Math.min(widthCm, heightCm);
    const longSide = Math.max(widthCm, heightCm);

    return (
      shortSide >= config.minWidthCm
      && shortSide <= config.maxWidthCm
      && longSide >= config.minHeightCm
      && longSide <= config.maxHeightCm
    );
  }

  private buildDimensionOptions(config: {
    minWidthCm: number;
    minHeightCm: number;
    maxWidthCm: number;
    maxHeightCm: number;
  }): number[] {
    const min = Math.min(config.minWidthCm, config.minHeightCm);
    const max = Math.max(config.maxWidthCm, config.maxHeightCm);
    const options: number[] = [];

    for (let value = min; value <= max; value += 10) {
      options.push(value);
    }

    return options;
  }

  private resolveSelectedValue(selectedValue: number | null, options: number[], preferredValue: number): number {
    if (selectedValue !== null && options.includes(selectedValue)) {
      return selectedValue;
    }

    if (options.includes(preferredValue)) {
      return preferredValue;
    }

    return options[0] ?? 0;
  }

  private buildPageContent(pagesConfig: { commissions?: { steps?: Array<{ image: string; imageAlt: { it: string; en: string } }>; testimonials?: CommissionsContent['reflections'] } }): CommissionsContent {
    const defaultContent = COMMISSIONS_CONTENT;
    const configuredSteps = Array.isArray(pagesConfig.commissions?.steps) ? pagesConfig.commissions.steps : [];
    const configuredTestimonials = Array.isArray(pagesConfig.commissions?.testimonials) ? pagesConfig.commissions.testimonials : [];

    return {
      ...defaultContent,
      steps: defaultContent.steps.map((step, index) => ({
        ...step,
        image: configuredSteps[index]?.image || step.image,
        imageAlt: configuredSteps[index]?.imageAlt || step.imageAlt
      })),
      reflections: defaultContent.reflections.map((reflection, index) => ({
        ...reflection,
        author: configuredTestimonials[index]?.author || reflection.author,
        context: configuredTestimonials[index]?.context || reflection.context,
        quote: configuredTestimonials[index]?.quote || reflection.quote,
        image: configuredTestimonials[index]?.image || reflection.image,
        imageAlt: configuredTestimonials[index]?.imageAlt || reflection.imageAlt
      }))
    };
  }
}
